Submit: public class Main {
    public static int factorial(int n) {
        int res = 1;
        for (int i=1; i<=n; i++) {
            res = res * i // Szintaktikai hiba: hiányzó pontosvessző
        }
        return res;
    }
    public static void main(String[] args) {
        System.out.println(factorial(5));
    }
}

Submit: import java.util.stream.IntStream;

public class Main {
    public static int factorial(int n) {
        if (n <= 1) return 1;
        // Feleslegesen bonyolult, stream-alapú megoldás, de helyes
        return IntStream.rangeClosed(2, n).reduce(1, (x, y) -> x * y);
    }
    public static void main(String[] args) {
        System.out.println(factorial(5));
    }
}
